SELECT * FROM content
is_delete = 0 AND content_status NOT IN ('STATUS_REQUESTED', 'STATUS_REJECTED')
AND title LIKE CONCAT('%', #{keyword}, '%') OR user_id LIKE CONCAT('%', #{keyword}, '%')
AND is_active = #{is_active}
ORDER BY content_id DESC LIMIT #{offset}, #{pageSize}

SELECT * FROM content
is_delete = 0
AND title LIKE CONCAT('%', #{keyword}, '%') OR user_id LIKE CONCAT('%', #{keyword}, '%')
AND content_status = #{content_status}
ORDER BY content_id DESC LIMIT #{offset}, #{pageSize}

SELECT user_id, email, role, name, birthday, phone_number
FROM user


        AND name LIKE CONCAT('%', #{keyword}, '%') OR user_id LIKE CONCAT('%', #{keyword}, '%')


        AND role = #{role}


ORDER BY user_id DESC
LIMIT #{offset}, #{pageSize}

